import React from 'react';
import QuestionList from '../components/QuestionList';

const Home = () => {
  return (
    <div style={{ padding: '20px' }}>
      <h1>All Questions</h1>

      {/* Uncomment only after QuestionList is fixed */}
      {/* <QuestionList /> */}

      <p style={{ color: 'green', fontSize: '20px', marginTop: '30px' }}>
        QuestionList is temporarily disabled — if you see this green text,{' '}
        <strong>the crash happens when QuestionList tries to render</strong>.
      </p>

      <p style={{ color: '#555', marginTop: '20px' }}>
        Next step: Fix QuestionList.js (most likely undefined data or .map crash).
      </p>
    </div>
  );
};

export default Home;
